import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { WheelStateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/WheelStateParser';

export class WheelStateEvent extends MessageEvent implements IMessageEvent {
    constructor(cb: (e: WheelStateEvent) => void) {
        super(cb, WheelStateParser);
    }
    public getParser(): WheelStateParser {
        return this.parser as WheelStateParser;
    }
}
